                      (sat["Position"][[1]] - Cos[target[[1]]]Cos[target[[2]]])^2 +
                      (sat["Position"][[2]] - Cos[target[[1]]]Sin[target[[2]]])^2 +
                      (sat["Position"][[3]] - Sin[target[[1]]])^2
